    "content": "use teloxide::prelude::*;
use teloxide::utils::command::BotCommands;
use sysinfo::{CpuExt, System, SystemExt};
use std::sync::Arc;
use tokio::sync::Mutex;

#[derive(BotCommands, Clone)]
#[command(renamed = "lowercase", description = "可用命令")]
enum Command {
    #[command(description = "开始使用")]
    Start,
    #[command(description = "帮助信息")]
    Help,
    #[command(description = "CPU 和内存使用率")]
    Cpu,
}

#[tokio::main]
async fn main() {
    pretty_env_logger::init();
    log::info!("🤖 正在启动 Rust Telegram Bot...");

    let bot_token = std::env::var("TELEGRAM_BOT_TOKEN")
        .expect("❌ 请设置环境变量 TELEGRAM_BOT_TOKEN");

    let bot = Bot::new(bot_token);

    // 获取机器人信息
    match bot.get_me().await {
        Ok(me) => {
            log::info!("✅ Bot 已连接：@{}", me.username.unwrap_or_default());
            log::info!("📱 在 Telegram 中发送消息给 Bot 开始对话");
            log::info!("💡 发送 'CPU' 或 /cpu 获取系统资源使用情况");
        }
        Err(e) => {
            log::error!("❌ 连接失败：{}", e);
            return;
        }
    }

    let system = Arc::new(Mutex::new(System::new()));

    Dispatcher::builder(bot, update_handler(system))
        .build()
        .setup_ctrlc_handler()
        .dispatch()
        .await;
}

fn update_handler(
    system: Arc<Mutex<System>>,
) -> UpdateHandler<teloxide::types::Me> {
    use dptree::case;

    let command_handler = teloxide::filter_command::<BotCommands, _>()
        .branch(case![Command::Start].endpoint(start_handler))
        .branch(case![Command::Help].endpoint(help_handler))
        .branch(case![Command::Cpu].endpoint(cpu_handler));

    let text_handler = dptree::filter(|msg: Message| msg.text().is_some())
        .endpoint(|bot: Bot, msg: Message| async move {
            bot.send_message(msg.chat.id, format!("📨 收到：{}", msg.text().unwrap())).await
        });

    command_handler.or(text_handler).inject(system)
}

async fn start_handler(bot: Bot, msg: Message) -> teloxide::RequestResult<()> {
    bot.send_message(msg.chat.id, 
        "👋 欢迎！我是 Rust Telegram Bot\n\
         📡 可用功能：\n\
         • 发送 'CPU' 或 /cpu - 获取系统资源报告\n\
         • /help - 显示帮助"
    ).await
}

async fn help_handler(bot: Bot, msg: Message) -> teloxide::RequestResult<()> {
    bot.send_message(msg.chat.id, 
        "🔹 **可用命令**\n\n\
         /start - 开始使用\n\
         /help - 帮助信息\n\
         /cpu - CPU 和内存使用率\n\n\
         🔹 **关键词**\n\
         发送 'CPU' 也可以触发资源报告"
    ).await
}

async fn cpu_handler(
    bot: Bot, 
    msg: Message, 
    system: Arc<Mutex<System>>,
) -> teloxide::RequestResult<()> {
    let mut sys = system.lock().await;
    sys.refresh_cpu();
    sys.refresh_memory();

    let cpu_usage = sys.global_cpu_usage();
    let memory = sys.total_memory();
    let used_memory = sys.used_memory();
    let memory_usage = (used_memory as f32 / memory as f32) * 100.0;

    let report = format!(
        "📊 **系统资源报告**\n\n\
         🖥️ CPU 使用率：{:.1}%\n\
         💾 内存使用：{:.1}% ({:.0} MB / {:.0} MB)",
        cpu_usage,
        memory_usage,
        used_memory / 1024 / 1024,
        memory / 1024 / 1024
    );

    bot.send_message(msg.chat.id, report).await
